		int array[] = {1,3,2,4,5,11,8};
		int temp;
		int arrlength=array.length;
		for(int i=0;i<arrlength;i++) {
			for(int j=i+1;j<arrlength;j++) {
				if(array[i]>array[j]) {
					temp = array[i];
					array[i]=array[j];
					array[j]=temp;
				}
