package javacode.arrays;

import java.util.Scanner;

public class SingleDimentionalArrayExample {

	public static void main(String[] args) {
		int arr[] = new int[4];
		Scanner scan = new Scanner(System.in);
		for (int i = 0; i < 4; i++) {
			System.out.println("Enter Number-" + i + ":");
			arr[i] = scan.nextInt();
		}
		System.out.println("Printing Single Dimentional Array");
		System.out.println("*********************************");
		for (int i = 0; i < 4; i++) {

			System.out.println("arr[" + i + "] = " + arr[i]);
		}
		scan.close();
	}
}

package javacode.arrays;

import java.util.Scanner;

public class ThreeDimentionalArray {

	public static void main(String[] args) {

		// THREE DIMENTIONAL ARRAY

		int threedim[][][] = new int[2][2][2];
		Scanner scan = new Scanner(System.in);

		for (int i = 0; i < 2; i++) {
			for (int j = 0; j < 2; j++) {
				for (int k = 0; k < 2; k++) {

					System.out.println("Enter Number - " + i + "," + j + "," + k + ":");
					threedim[i][j][k] = scan.nextInt();

				}

			}
		}

		System.out.println("Printing Three Dimentional Array");
		System.out.println("*********************************");

		for (int i = 0; i < 2; i++) {
			for (int j = 0; j < 2; j++) {
				for (int k = 0; k < 2; k++) {

					System.out.println("arr[" + i + "][" + j + "]" + "[" + j + "]= " + threedim[i][j][k]);

				}

			}
		}

		scan.close();

	}

}

package javacode.arrays;

import java.util.Scanner;

public class TwoDimentionalArraysExamples {

	public static void main(String[] args) {

		// TWO DIMENTIONAL ARRAY

		int multi[][] = new int[2][2];
		Scanner scan = new Scanner(System.in);

		for (int i = 0; i < 2; i++) {
			for (int j = 0; j < 2; j++) {
				System.out.println("Enter Number - " + i + "," + j + ":");
				multi[i][j] = scan.nextInt();
			}
		}

		System.out.println("Printing Double Dimentional Array");
		System.out.println("*********************************");
		for (int i = 0; i < 2; i++) {
			for (int j = 0; j < 2; j++) {

				System.out.println("arr[" + i + "]" + "[" + j + "]" + " = " + multi[i][j]);
			}
		}
		scan.close();

	}

}

